solutions.javascript:
// Solution
function insert(word, root) {
  if (word === '') return false;
  let node = root;
  for (let i = 0; i < word.length; i++) {
    if (!node.children[word[i]]) node.children[word[i]] = {};
    node = node.children[word[i]];
  }
  return true;
}
